+// ---------------------------------------------------------------------------
+// Global evidence ledger singleton
+// ---------------------------------------------------------------------------
+
+static GLOBAL_LEDGER: OnceLock<EvidenceLedger> = OnceLock::new();
+
+/// Get the global evidence ledger singleton.
+///
+/// Lazily initialised with a 1000-entry in-memory ring buffer. If
