+        cache.insert("a", 10);
+        // Insert "b" -> evicts "a" from small. "a" has freq=0 -> goes to ghost
+        cache.insert("b", 20);
+
+        assert_eq!(cache.get(&"a"), None); // "a" is in ghost, not visible
+        assert_eq!(cache.ghost_len(), 1);
+
+        // Re-insert "a" -> should go to Main (ghost hit)
+        cache.insert("a", 100);
